const transcript = ($json.transcript || '').toLowerCase();
const event = ($json.event || '').toUpperCase();
const confidence = Number($json.confidence || 0);
const riskScore = Number($json.riskScore || 0);
const complaintCount = Number($json.complaintCount || 0);
const customerTier = ($json.customerTier || 'NORMAL').toUpperCase();
const claimAmount = Number($json.claimAmount || 0);

let nextAction = 'UNDER_REVIEW';
let workflowStatus = 'UNDER_REVIEW';
let activeAgent = 'Intake Agent';
let humanReviewRequired = false;
let escalationLevel = 'NONE';
let ethicalGuardrail = 'PASSED';
let autonomousAllowed = true;
let timelineMessage = 'Claim received and queued.';

if (riskScore >= 75) {
  autonomousAllowed = false;
  humanReviewRequired = true;
  ethicalGuardrail = 'HIGH_RISK_REQUIRES_HUMAN';
}

if (claimAmount > 5000) {
  autonomousAllowed = false;
  humanReviewRequired = true;
  ethicalGuardrail = 'HIGH_VALUE_REFUND_REQUIRES_HUMAN';
}

if (complaintCount >= 3) {
  humanReviewRequired = true;
  escalationLevel = 'FRAUD_REVIEW';
}

if (confidence >= 0.95) {
  humanReviewRequired = true;
  escalationLevel = 'CRITICAL';
}

if (transcript.includes('damage') || transcript.includes('broken') || transcript.includes('screen') || event === 'VISION_AGENT_STARTED') {
  nextAction = 'VISION_VERIFY';
  workflowStatus = 'VERIFICATION_RUNNING';
  activeAgent = 'Vision Agent';
  timelineMessage = 'Vision verification initiated.';
}

if (event === 'POSSIBLE_DAMAGE_DETECTED' || riskScore >= 70 || confidence >= 0.9) {
  nextAction = 'ESCALATE';
  workflowStatus = 'ESCALATED';
  activeAgent = 'Fraud Agent';
  humanReviewRequired = true;
  escalationLevel = 'HIGH';
  timelineMessage = 'Possible anomaly detected. Human review required.';
}

if (transcript.includes('refund') || transcript.includes('replace') || event === 'RESOLUTION_REQUESTED') {
  nextAction = 'RESOLUTION';
  workflowStatus = 'RESOLUTION_RUNNING';
  activeAgent = 'Resolution Agent';
  timelineMessage = 'Resolution workflow started.';
}

if (event === 'MORE_EVIDENCE_REQUIRED') {
  nextAction = 'REQUEST_EVIDENCE';
  workflowStatus = 'WAITING_FOR_EVIDENCE';
  activeAgent = 'Evidence Agent';
  timelineMessage = 'Additional evidence requested.';
}

if (autonomousAllowed === false && nextAction === 'RESOLUTION') {
  nextAction = 'ESCALATE';
  workflowStatus = 'HUMAN_APPROVAL_REQUIRED';
  activeAgent = 'Governance Agent';
  timelineMessage = 'Human approval required due to governance policies.';
}

const timelineEvent = {
  eventType: event || 'UNKNOWN',
  actor: activeAgent,
  eventMessage: timelineMessage,
  eventTimestamp: new Date().toISOString()
};

const auditTrail = {
  timestamp: new Date().toISOString(),
  ticketId: $json.ticketId,
  activeAgent,
  workflowStatus,
  escalationLevel,
  ethicalGuardrail,
  autonomousAllowed
};

return [{
  json: {
    ...$json,
    nextAction,
    workflowStatus,
    activeAgent,
    humanReviewRequired,
    escalationLevel,
    ethicalGuardrail,
    autonomousAllowed,
    timelineEvent,
    auditTrail,
    liveJourneyUpdate: {
      currentStage: workflowStatus,
      activeAgent,
      updatedAt: new Date().toISOString()
    },
    journeyUpdate: timelineMessage
  }
}];

const workflowStatus = $json.workflowStatus;
const activeAgent = $json.activeAgent;
const timeline = Array.isArray($json.timeline) ? $json.timeline : [];

let journeyStage = 'UNDER_REVIEW';

if (workflowStatus === 'VERIFICATION_RUNNING') journeyStage = 'VISION_VERIFICATION';
if (workflowStatus === 'ESCALATED') journeyStage = 'HUMAN_REVIEW';
if (workflowStatus === 'RESOLUTION_RUNNING') journeyStage = 'RESOLUTION';
if (workflowStatus === 'WAITING_FOR_EVIDENCE') journeyStage = 'AWAITING_CUSTOMER';
if (workflowStatus === 'HUMAN_APPROVAL_REQUIRED') journeyStage = 'HUMAN_APPROVAL_REQUIRED';

const appendedTimelineEvent = {
  timestamp: new Date().toISOString(),
  actor: activeAgent,
  stage: journeyStage,
  message: $json.timelineEvent?.eventMessage || 'Journey updated'
};

return [{
  json: {
    ...$json,
    journeyStage,
    timeline: [...timeline, appendedTimelineEvent],
    liveJourneyUpdate: {
      currentStage: journeyStage,
      activeAgent,
      updatedAt: new Date().toISOString()
    },
    auditTrail: {
      ...( $json.auditTrail || {} ),
      journeyStage,
      appendedTimelineEvent
    }
  }
}];

const ethicalGuardrail = $json.ethicalGuardrail || 'PASSED';
const autonomousAllowed = Boolean($json.autonomousAllowed);
const humanReviewRequired = Boolean($json.humanReviewRequired);
const riskScore = Number($json.riskScore || 0);
const claimAmount = Number($json.claimAmount || 0);

let nextAction = $json.nextAction;
let workflowStatus = $json.workflowStatus;
let governanceDecision = 'AUTONOMOUS_ALLOWED';

if (riskScore >= 75 || claimAmount > 5000 || ethicalGuardrail !== 'PASSED') {
  nextAction = 'ESCALATE';
  workflowStatus = 'HUMAN_APPROVAL_REQUIRED';
  governanceDecision = 'HUMAN_REVIEW_REQUIRED';
}

if (humanReviewRequired) {
  nextAction = 'ESCALATE';
  workflowStatus = 'ESCALATED';
  governanceDecision = 'HUMAN_REVIEW_REQUIRED';
}

return [{
  json: {
    ...$json,
    nextAction,
    workflowStatus,
    governanceDecision,
    governanceAudit: {
      timestamp: new Date().toISOString(),
      ticketId: $json.ticketId,
      ethicalGuardrail,
      autonomousAllowed,
      humanReviewRequired,
      riskScore,
      claimAmount,
      governanceDecision
    }
  }
}];

